import{_ as t,o as s,c as l,a3 as a}from"./chunks/framework.DTo1Fhyx.js";const d=JSON.parse('{"title":"Kubernetes 是什么？","description":"","frontmatter":{},"headers":[],"relativePath":"docs/SystematicKnowledge/Kubernetes/what-is-kubernetes.md","filePath":"docs/SystematicKnowledge/Kubernetes/what-is-kubernetes.md","lastUpdated":1732000493000}'),o={name:"docs/SystematicKnowledge/Kubernetes/what-is-kubernetes.md"};function i(c,e,r,n,u,p){return s(),l("div",null,e[0]||(e[0]=[a('<h1 id="what-is-kubernetes" tabindex="-1">Kubernetes 是什么？ <a class="header-anchor" href="#what-is-kubernetes" aria-label="Permalink to &quot;Kubernetes 是什么？ {#what-is-kubernetes}&quot;">​</a></h1><h2 id="kubernetes" tabindex="-1">Kubernetes简介 <a class="header-anchor" href="#kubernetes" aria-label="Permalink to &quot;Kubernetes简介 {#kubernetes}&quot;">​</a></h2><ol><li><a href="https://landscape.cncf.io" target="_blank" rel="noreferrer">CNCF</a></li><li><a href="https://kubernetes.io" target="_blank" rel="noreferrer">Production-Grade Container Orchestration</a></li></ol><p>Kubernetes 也称为 K8s，是用于自动部署、扩缩和管理容器化应用程序的开源系统。</p><p>它将组成应用程序的容器组合成逻辑单元，以便于管理和服务发现。Kubernetes 源自Google 15 年生产环境的运维经验，同时凝聚了社区的最佳创意和实践。</p><ol><li>星际尺度</li></ol><ul><li>Google 每周运行数十亿个容器，Kubernetes 基于与之相同的原则来设计，能够在不扩张运维团队的情况下进行规模扩展。</li></ul><ol start="2"><li>永不过时</li></ol><ul><li>无论是本地测试，还是跨国公司，Kubernetes 的灵活性都能让你在应对复杂系统时得心应手。</li></ul><ol start="3"><li>处处适用</li></ol><ul><li>Kubernetes 是开源系统，可以自由地部署在企业内部，私有云、混合云或公有云，让您轻松地做出合适的选择。</li></ul><h2 id="kubernetes-特性" tabindex="-1">Kubernetes 特性 <a class="header-anchor" href="#kubernetes-特性" aria-label="Permalink to &quot;Kubernetes 特性&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">自动化上线和回滚</p><p>Kubernetes 会分步骤地将针对应用或其配置的更改上线，同时监视应用程序运行状况以确保你不会同时终止所有实例。如果出现问题，Kubernetes 会为你回滚所作更改。你应该充分利用不断成长的部署方案生态系统。</p></div><div class="tip custom-block"><p class="custom-block-title">服务发现与负载均衡</p><p>你无需修改应用来使用陌生的服务发现机制。Kubernetes 为每个 Pod 提供了自己的 IP 地址并为一组 Pod 提供一个 DNS 名称，并且可以在它们之间实现负载均衡。</p></div><div class="tip custom-block"><p class="custom-block-title">自我修复</p><p>重新启动失败的容器，在节点死亡时替换并重新调度容器， 杀死不响应用户定义的健康检查的容器， 并且在它们准备好服务之前不会将它们公布给客户端。</p></div><div class="tip custom-block"><p class="custom-block-title">存储编排</p><p>自动挂载所选存储系统，包括本地存储、公有云提供商所提供的存储或者诸如 iSCSI 或 NFS 这类网络存储系统。</p></div><div class="tip custom-block"><p class="custom-block-title">自Secret 和配置管理</p><p>部署和更新 Secret 和应用程序的配置而不必重新构建容器镜像， 且不必将软件堆栈配置中的秘密信息暴露出来。</p></div><div class="tip custom-block"><p class="custom-block-title">自动装箱</p><p>根据资源需求和其他限制自动放置容器，同时避免影响可用性。 将关键性的和尽力而为性质的工作负载进行混合放置，以提高资源利用率并节省更多资源。</p></div><div class="tip custom-block"><p class="custom-block-title">批量执行</p><p>除了服务之外，Kubernetes 还可以管理你的批处理和 CI 工作负载，在期望时替换掉失效的容器。</p></div><div class="tip custom-block"><p class="custom-block-title">IPv4/IPv6 双协议栈</p><p>为 Pod 和 Service 分配 IPv4 和 IPv6 地址。</p></div><div class="tip custom-block"><p class="custom-block-title">水平扩缩</p><p>使用一个简单的命令、一个 UI 或基于 CPU 使用情况自动对应用程序进行扩缩。</p></div><div class="tip custom-block"><p class="custom-block-title">为扩展性设计</p><p>无需更改上游源码即可扩展你的 Kubernetes 集群。</p></div>',22)]))}const k=t(o,[["render",i]]);export{d as __pageData,k as default};
